oxy_webhelp_navlinks = {"tocId-d30753e41363":{"topics":[{"title":"Cloud storage cost considerations for <span class=\"ph\">NAS CD<\/span> data sets","shortdesc":"<p class=\"shortdesc\">When protecting cloud-hosted data with <span class=\"ph\">NAS CD<\/span>, you must consider how         the storage tier selection and data retrieval pricing of your cloud provider affect your         backup and scanning costs.<\/p>","href":"saas\/rncd_cloud_storage_cost_considerations.html","attributes":{"data-id":"rncd_cloud_storage_cost_considerations"},"menu":{"hasChildren":false},"tocID":"rncd_cloud_storage_cost_considerations-d30753e41364","topics":[]},{"title":"RBAC for <span class=\"ph\">RSC<\/span>-based protection","shortdesc":"<p class=\"shortdesc\">You can use role-based access control to assign a role containing a set of         permissions to a <span class=\"ph\">RSC<\/span> user. You can also assign multiple roles to a         user.<\/p>","href":"saas\/rncd_rbac_rsc_based_protection.html","attributes":{"data-id":"rncd_rbac_rsc_based_protection"},"menu":{"hasChildren":false},"tocID":"rncd_rbac_rsc_based_protection-d30753e41381","next":"rncd_rbac_rsc_based_protection-d30753e41381"}]}};